// ─── Build Final Parks Data ───────────────────────────────────────────────────
export const parksData = rawParks.map(park => {
  const idStr = park.id.toString().padStart(2, '0');
  let archiveFile = `${idStr}_${park.name.replace(/ /g, '_')}_National_Park.jpg`;
  if (park.name === "Black Canyon")       archiveFile = `${idStr}_Black_Canyon_of_the_Gunnison.jpg`;
  if (park.name === "Great Smoky Mountains") archiveFile = `${idStr}_Great_Smoky_Mountains.jpg`;
  if (park.name === "Hawaiʻi Volcanoes")  archiveFile = `${idStr}_Hawai_i_Volcanoes_National_Park.jpg`;
  if (park.name === "Big Bend")           archiveFile = `${idStr}_Big_Bend_National_Park.jpeg`;
  if (park.name === "Great Sand Dunes")   archiveFile = `${idStr}_Great_Sand_Dunes_National_Park.jpg`;
  if (park.name === "American Samoa")     archiveFile = `${idStr}_National_Park_of_American_Samoa.jpg`;
  if (park.name === "Haleakalā")          archiveFile = `${idStr}_Haleakal_National_Park.jpg`;
  if (park.name === "Wrangell–St. Elias") archiveFile = `${idStr}_Wrangell_St_Elias_National_Park.jpg`;

  const archivalImage = `/parks/archival/${archiveFile}`;
  const featured = featuredAssets[park.id] || {};

  return {
    ...park,
    image: archivalImage,
    heroPhoto: featured.heroPhoto || archivalImage,
    heroVideo: featured.heroVideo || null,
  };
});

export default parksData;
